1506   /// Fuse two fusion candidates, creating a new fused loop.
1507   ///
1508   /// This method contains the mechanics of fusing two loops, represented by \p
1509   /// FC0 and \p FC1. It is assumed that \p FC0 dominates \p FC1 and \p FC1
1510   /// postdominates \p FC0 (making them control flow equivalent). It also
1511   /// assumes that the other conditions for fusion have been met: adjacent,
1512   /// identical trip counts, and no negative distance dependencies exist that
1513   /// would prevent fusion. Thus, there is no checking for these conditions in
1514   /// this method.
1515   ///
1516   /// Fusion is performed by rewiring the CFG to update successor blocks of the
1517   /// components of tho loop. Specifically, the following changes are done:
1518   ///
1519   ///   1. The preheader of \p FC1 is removed as it is no longer necessary
1520   ///   (because it is currently only a single statement block).
1521   ///   2. The latch of \p FC0 is modified to jump to the header of \p FC1.
1522   ///   3. The latch of \p FC1 i modified to jump to the header of \p FC0.
1523   ///   4. All blocks from \p FC1 are removed from FC1 and added to FC0.
1524   ///
1525   /// All of these modifications are done with dominator tree updates, thus
1526   /// keeping the dominator (and post dominator) information up-to-date.
1527   ///
1528   /// This can be improved in the future by actually merging blocks during
1529   /// fusion. For example, the preheader of \p FC1 can be merged with the
1530   /// preheader of \p FC0. This would allow loops with more than a single
1531   /// statement in the preheader to be fused. Similarly, the latch blocks of the
1532   /// two loops could also be fused into a single block. This will require
1533   /// analysis to prove it is safe to move the contents of the block past
1534   /// existing code, which currently has not been implemented.
1535   Loop *performFusion(const FusionCandidate &FC0, const FusionCandidate &FC1) {
1536     assert(FC0.isValid() && FC1.isValid() &&
1537            "Expecting valid fusion candidates");
1538 
1539     LLVM_DEBUG(dbgs() << "Fusion Candidate 0: \n"; FC0.dump();
1540                dbgs() << "Fusion Candidate 1: \n"; FC1.dump(););
1541 
1542     // Move instructions from the preheader of FC1 to the end of the preheader
1543     // of FC0.
1544     moveInstructionsToTheEnd(*FC1.Preheader, *FC0.Preheader, DT, PDT, DI);
1545 
1546     // Fusing guarded loops is handled slightly differently than non-guarded
1547     // loops and has been broken out into a separate method instead of trying to
1548     // intersperse the logic within a single method.
1549     if (FC0.GuardBranch)
1550       return fuseGuardedLoops(FC0, FC1);
1551 
1552     assert(FC1.Preheader ==
1553            (FC0.Peeled ? FC0.ExitBlock->getUniqueSuccessor() : FC0.ExitBlock));
1554     assert(FC1.Preheader->size() == 1 &&
1555            FC1.Preheader->getSingleSuccessor() == FC1.Header);
1556 
1557     // Remember the phi nodes originally in the header of FC0 in order to rewire
1558     // them later. However, this is only necessary if the new loop carried
1559     // values might not dominate the exiting branch. While we do not generally
1560     // test if this is the case but simply insert intermediate phi nodes, we
1561     // need to make sure these intermediate phi nodes have different
1562     // predecessors. To this end, we filter the special case where the exiting
1563     // block is the latch block of the first loop. Nothing needs to be done
1564     // anyway as all loop carried values dominate the latch and thereby also the
1565     // exiting branch.
1566     SmallVector<PHINode *, 8> OriginalFC0PHIs;
1567     if (FC0.ExitingBlock != FC0.Latch)
1568       for (PHINode &PHI : FC0.Header->phis())
1569         OriginalFC0PHIs.push_back(&PHI);
1570 
1571     // Replace incoming blocks for header PHIs first.
1572     FC1.Preheader->replaceSuccessorsPhiUsesWith(FC0.Preheader);
1573     FC0.Latch->replaceSuccessorsPhiUsesWith(FC1.Latch);
1574 
1575     // Then modify the control flow and update DT and PDT.
1576     SmallVector<DominatorTree::UpdateType, 8> TreeUpdates;
1577 
1578     // The old exiting block of the first loop (FC0) has to jump to the header
1579     // of the second as we need to execute the code in the second header block
1580     // regardless of the trip count. That is, if the trip count is 0, so the
1581     // back edge is never taken, we still have to execute both loop headers,
1582     // especially (but not only!) if the second is a do-while style loop.
1583     // However, doing so might invalidate the phi nodes of the first loop as
1584     // the new values do only need to dominate their latch and not the exiting
1585     // predicate. To remedy this potential problem we always introduce phi
1586     // nodes in the header of the second loop later that select the loop carried
1587     // value, if the second header was reached through an old latch of the
1588     // first, or undef otherwise. This is sound as exiting the first implies the
1589     // second will exit too, __without__ taking the back-edge. [Their
1590     // trip-counts are equal after all.
1591     // KB: Would this sequence be simpler to just make FC0.ExitingBlock go
1592     // to FC1.Header? I think this is basically what the three sequences are
1593     // trying to accomplish; however, doing this directly in the CFG may mean
1594     // the DT/PDT becomes invalid
1595     if (!FC0.Peeled) {
1596       FC0.ExitingBlock->getTerminator()->replaceUsesOfWith(FC1.Preheader,
1597                                                            FC1.Header);
1598       TreeUpdates.emplace_back(DominatorTree::UpdateType(
1599           DominatorTree::Delete, FC0.ExitingBlock, FC1.Preheader));
1600       TreeUpdates.emplace_back(DominatorTree::UpdateType(
1601           DominatorTree::Insert, FC0.ExitingBlock, FC1.Header));
1602     } else {
1603       TreeUpdates.emplace_back(DominatorTree::UpdateType(
1604           DominatorTree::Delete, FC0.ExitBlock, FC1.Preheader));
1605 
1606       // Remove the ExitBlock of the first Loop (also not needed)
1607       FC0.ExitingBlock->getTerminator()->replaceUsesOfWith(FC0.ExitBlock,
1608                                                            FC1.Header);
1609       TreeUpdates.emplace_back(DominatorTree::UpdateType(
1610           DominatorTree::Delete, FC0.ExitingBlock, FC0.ExitBlock));
1611       FC0.ExitBlock->getTerminator()->eraseFromParent();
1612       TreeUpdates.emplace_back(DominatorTree::UpdateType(
1613           DominatorTree::Insert, FC0.ExitingBlock, FC1.Header));
1614       new UnreachableInst(FC0.ExitBlock->getContext(), FC0.ExitBlock);
1615     }
1616 
1617     // The pre-header of L1 is not necessary anymore.
1618     assert(pred_empty(FC1.Preheader));
1619     FC1.Preheader->getTerminator()->eraseFromParent();
1620     new UnreachableInst(FC1.Preheader->getContext(), FC1.Preheader);
1621     TreeUpdates.emplace_back(DominatorTree::UpdateType(
1622         DominatorTree::Delete, FC1.Preheader, FC1.Header));
