1624     // Moves the phi nodes from the second to the first loops header block.
1625     while (PHINode *PHI = dyn_cast<PHINode>(&FC1.Header->front())) {
1626       if (SE.isSCEVable(PHI->getType()))
1627         SE.forgetValue(PHI);
