1139   /// Rewrite all additive recurrences in a SCEV to use a new loop.
1140   class AddRecLoopReplacer : public SCEVRewriteVisitor<AddRecLoopReplacer> {
1141   public:
1142     AddRecLoopReplacer(ScalarEvolution &SE, const Loop &OldL, const Loop &NewL,
1143                        bool UseMax = true)
1144         : SCEVRewriteVisitor(SE), Valid(true), UseMax(UseMax), OldL(OldL),
1145           NewL(NewL) {}
1146 
1147     const SCEV *visitAddRecExpr(const SCEVAddRecExpr *Expr) {
1148       const Loop *ExprL = Expr->getLoop();
1149       SmallVector<const SCEV *, 2> Operands;
1150       if (ExprL == &OldL) {
1151         append_range(Operands, Expr->operands());
1152         return SE.getAddRecExpr(Operands, &NewL, Expr->getNoWrapFlags());
1153       }
1154 
1155       if (OldL.contains(ExprL)) {
1156         bool Pos = SE.isKnownPositive(Expr->getStepRecurrence(SE));
1157         if (!UseMax || !Pos || !Expr->isAffine()) {
1158           Valid = false;
1159           return Expr;
1160         }
1161         return visit(Expr->getStart());
1162       }
1163 
1164       for (const SCEV *Op : Expr->operands())
1165         Operands.push_back(visit(Op));
1166       return SE.getAddRecExpr(Operands, ExprL, Expr->getNoWrapFlags());
1167     }
1168 
1169     bool wasValidSCEV() const { return Valid; }
1170 
1171   private:
1172     bool Valid, UseMax;
1173     const Loop &OldL, &NewL;
1174   };
