1669 
1670     TreeUpdates.emplace_back(DominatorTree::UpdateType(DominatorTree::Delete,
1671                                                        FC0.Latch, FC0.Header));
1672     TreeUpdates.emplace_back(DominatorTree::UpdateType(DominatorTree::Insert,
1673                                                        FC1.Latch, FC0.Header));
