1715       const auto &ChildLoopIt = FC1.L->begin();
1716       Loop *ChildLoop = *ChildLoopIt;
1717       FC1.L->removeChildLoop(ChildLoopIt);
1718       FC0.L->addChildLoop(ChildLoop);
1719     }
1720 
1721     // Delete the now empty loop L1.
1722     LI.erase(FC1.L);
