1796         (FC0.Peeled ? *FC0ExitBlockSuccessor : *FC0.ExitBlock), *FC1.ExitBlock,
1797         DT, PDT, DI);
1798 
1799     // Move instructions from the guard block of FC1 to the end of the guard
1800     // block of FC0.
1801     moveInstructionsToTheEnd(*FC1GuardBlock, *FC0GuardBlock, DT, PDT, DI);
1802 
1803     assert(FC0NonLoopBlock == FC1GuardBlock && "Loops are not adjacent");
1804 
1805     SmallVector<DominatorTree::UpdateType, 8> TreeUpdates;
1806 
1807     ////////////////////////////////////////////////////////////////////////////
1808     // Update the Loop Guard
1809     ////////////////////////////////////////////////////////////////////////////
1810     // The guard for FC0 is updated to guard both FC0 and FC1. This is done by
1811     // changing the NonLoopGuardBlock for FC0 to the NonLoopGuardBlock for FC1.
1812     // Thus, one path from the guard goes to the preheader for FC0 (and thus
1813     // executes the new fused loop) and the other path goes to the NonLoopBlock
1814     // for FC1 (where FC1 guard would have gone if FC1 was not executed).
1815     FC1NonLoopBlock->replacePhiUsesWith(FC1GuardBlock, FC0GuardBlock);
1816     FC0.GuardBranch->replaceUsesOfWith(FC0NonLoopBlock, FC1NonLoopBlock);
1817 
1818     BasicBlock *BBToUpdate = FC0.Peeled ? FC0ExitBlockSuccessor : FC0.ExitBlock;
1819     BBToUpdate->getTerminator()->replaceUsesOfWith(FC1GuardBlock, FC1.Header);
1820 
1821     // The guard of FC1 is not necessary anymore.
1822     FC1.GuardBranch->eraseFromParent();
1823     new UnreachableInst(FC1GuardBlock->getContext(), FC1GuardBlock);
1824 
1825     TreeUpdates.emplace_back(DominatorTree::UpdateType(
1826         DominatorTree::Delete, FC1GuardBlock, FC1.Preheader));
1827     TreeUpdates.emplace_back(DominatorTree::UpdateType(
1828         DominatorTree::Delete, FC1GuardBlock, FC1NonLoopBlock));
1829     TreeUpdates.emplace_back(DominatorTree::UpdateType(
1830         DominatorTree::Delete, FC0GuardBlock, FC1GuardBlock));
1831     TreeUpdates.emplace_back(DominatorTree::UpdateType(
1832         DominatorTree::Insert, FC0GuardBlock, FC1NonLoopBlock));
