1834     if (FC0.Peeled) {
1835       // Remove the Block after the ExitBlock of FC0
1836       TreeUpdates.emplace_back(DominatorTree::UpdateType(
1837           DominatorTree::Delete, FC0ExitBlockSuccessor, FC1GuardBlock));
