1328       for (Instruction *WriteL1 : FC1.MemWrites)
1329         if (!dependencesAllowFusion(FC0, FC1, *WriteL0, *WriteL1,
1330                                     /* AnyDep */ false,
1331                                     FusionDependenceAnalysis)) {
1332           InvalidDependencies++;
1333           return false;
1334         }
1335       for (Instruction *ReadL1 : FC1.MemReads)
1336         if (!dependencesAllowFusion(FC0, FC1, *WriteL0, *ReadL1,
1337                                     /* AnyDep */ false,
1338                                     FusionDependenceAnalysis)) {
