1341         }
1342     }
1343 
1344     for (Instruction *WriteL1 : FC1.MemWrites) {
1345       for (Instruction *WriteL0 : FC0.MemWrites)
1346         if (!dependencesAllowFusion(FC0, FC1, *WriteL0, *WriteL1,
1347                                     /* AnyDep */ false,
1348                                     FusionDependenceAnalysis)) {
1349           InvalidDependencies++;
1350           return false;
1351         }
1352       for (Instruction *ReadL0 : FC0.MemReads)
1353         if (!dependencesAllowFusion(FC0, FC1, *ReadL0, *WriteL1,
1354                                     /* AnyDep */ false,
