1375   /// Determine if two fusion candidates are strictly adjacent in the CFG.
1376   ///
1377   /// This method will determine if there are additional basic blocks in the CFG
1378   /// between the exit of \p FC0 and the entry of \p FC1.
1379   /// If the two candidates are guarded loops, then it checks whether the
1380   /// exit block of the \p FC0 is the predecessor of the \p FC1 preheader. This
1381   /// implicitly ensures that the non-loop successor of the \p FC0 guard branch
1382   /// is the entry block of \p FC1. If not, then the loops are not adjacent. If
1383   /// the two candidates are not guarded loops, then it checks whether the exit
1384   /// block of \p FC0 is the preheader of \p FC1.
1385   /// Strictly means there is no predecessor for FC1 unless it is from FC0,
1386   /// i.e., FC0 dominates FC1.
1387   bool isStrictlyAdjacent(const FusionCandidate &FC0,
1388                           const FusionCandidate &FC1) const {
1389     // If the successor of the guard branch is FC1, then the loops are adjacent
1390     if (FC0.GuardBranch)
1391       return DT.dominates(FC0.getEntryBlock(), FC1.getEntryBlock()) &&
1392              FC0.ExitBlock->getSingleSuccessor() == FC1.getEntryBlock();
1393     else
1394       return FC0.ExitBlock == FC1.getEntryBlock();
1395   }
