1401   /// Hoist \p FC1 Preheader instructions to \p FC0 Preheader
1402   /// and sink others into the body of \p FC1.
1403   void movePreheaderInsts(const FusionCandidate &FC0,
1404                           const FusionCandidate &FC1,
1405                           SmallVector<Instruction *, 4> &HoistInsts,
1406                           SmallVector<Instruction *, 4> &SinkInsts) const {
1407     // All preheader instructions except the branch must be hoisted or sunk
1408     assert(HoistInsts.size() + SinkInsts.size() == FC1.Preheader->size() - 1 &&
1409            "Attempting to sink and hoist preheader instructions, but not all "
1410            "the preheader instructions are accounted for.");
1411 
1412     NumHoistedInsts += HoistInsts.size();
1413     NumSunkInsts += SinkInsts.size();
1414 
1415     LLVM_DEBUG(if (VerboseFusionDebugging) {
1416       if (!HoistInsts.empty())
1417         dbgs() << "Hoisting: \n";
1418       for (Instruction *I : HoistInsts)
1419         dbgs() << *I << "\n";
1420       if (!SinkInsts.empty())
1421         dbgs() << "Sinking: \n";
1422       for (Instruction *I : SinkInsts)
1423         dbgs() << *I << "\n";
1424     });
1425 
1426     for (Instruction *I : HoistInsts) {
1427       assert(I->getParent() == FC1.Preheader);
1428       I->moveBefore(*FC0.Preheader,
1429                     FC0.Preheader->getTerminator()->getIterator());
1430     }
1431     // insert instructions in reverse order to maintain dominance relationship
1432     for (Instruction *I : reverse(SinkInsts)) {
1433       assert(I->getParent() == FC1.Preheader);
1434       if (isa<PHINode>(I)) {
1435         // The Phis to be sunk should have only one incoming value, as is
1436         // assured by the condition that the second loop is dominated by the
1437         // first one which is enforced by isStrictlyAdjacent().
1438         // Replace the phi uses with the corresponding incoming value to clean
1439         // up the code.
1440         assert(cast<PHINode>(I)->getNumIncomingValues() == 1 &&
1441                "Expected the sunk PHI node to have 1 incoming value.");
1442         I->replaceAllUsesWith(I->getOperand(0));
1443         I->eraseFromParent();
1444       } else
1445         I->moveBefore(*FC1.ExitBlock, FC1.ExitBlock->getFirstInsertionPt());
1446     }
1447   }
