1449   /// Determine if two fusion candidates have identical guards
1450   ///
1451   /// This method will determine if two fusion candidates have the same guards.
1452   /// The guards are considered the same if:
1453   ///   1. The instructions to compute the condition used in the compare are
1454   ///      identical.
1455   ///   2. The successors of the guard have the same flow into/around the loop.
1456   /// If the compare instructions are identical, then the first successor of the
1457   /// guard must go to the same place (either the preheader of the loop or the
1458   /// NonLoopBlock). In other words, the first successor of both loops must
1459   /// both go into the loop (i.e., the preheader) or go around the loop (i.e.,
1460   /// the NonLoopBlock). The same must be true for the second successor.
1461   bool haveIdenticalGuards(const FusionCandidate &FC0,
1462                            const FusionCandidate &FC1) const {
1463     assert(FC0.GuardBranch && FC1.GuardBranch &&
1464            "Expecting FC0 and FC1 to be guarded loops.");
1465 
1466     if (auto FC0CmpInst =
1467             dyn_cast<Instruction>(FC0.GuardBranch->getCondition()))
1468       if (auto FC1CmpInst =
1469               dyn_cast<Instruction>(FC1.GuardBranch->getCondition()))
1470         if (!FC0CmpInst->isIdenticalTo(FC1CmpInst))
1471           return false;
1472 
1473     // The compare instructions are identical.
1474     // Now make sure the successor of the guards have the same flow into/around
1475     // the loop
1476     if (FC0.GuardBranch->getSuccessor(0) == FC0.Preheader)
1477       return (FC1.GuardBranch->getSuccessor(0) == FC1.Preheader);
1478     else
1479       return (FC1.GuardBranch->getSuccessor(1) == FC1.Preheader);
1480   }
