2037 PreservedAnalyses LoopFusePass::run(Function &F, FunctionAnalysisManager &AM) {
2038   auto &LI = AM.getResult<LoopAnalysis>(F);
2039   auto &DT = AM.getResult<DominatorTreeAnalysis>(F);
2040   auto &DI = AM.getResult<DependenceAnalysis>(F);
2041   auto &SE = AM.getResult<ScalarEvolutionAnalysis>(F);
2042   auto &PDT = AM.getResult<PostDominatorTreeAnalysis>(F);
2043   auto &ORE = AM.getResult<OptimizationRemarkEmitterAnalysis>(F);
2044   auto &AC = AM.getResult<AssumptionAnalysis>(F);
2045   const TargetTransformInfo &TTI = AM.getResult<TargetIRAnalysis>(F);
2046   const DataLayout &DL = F.getDataLayout();
2047 
2048   // Ensure loops are in simplifed form which is a pre-requisite for loop fusion
2049   // pass. Added only for new PM since the legacy PM has already added
2050   // LoopSimplify pass as a dependency.
2051   bool Changed = false;
2052   for (auto &L : LI) {
2053     Changed |=
2054         simplifyLoop(L, &DT, &LI, &SE, &AC, nullptr, false /* PreserveLCSSA */);
2055   }
2056   if (Changed)
2057     PDT.recalculate(F);
2058 
2059   LoopFuser LF(LI, DT, DI, SE, PDT, ORE, DL, AC, TTI);
2060   Changed |= LF.fuseLoops(F);
2061   if (!Changed)
2062     return PreservedAnalyses::all();
2063 
2064   PreservedAnalyses PA;
2065   PA.preserve<DominatorTreeAnalysis>();
2066   PA.preserve<PostDominatorTreeAnalysis>();
2067   PA.preserve<ScalarEvolutionAnalysis>();
2068   PA.preserve<LoopAnalysis>();
2069   return PA;
2070 }
